define(['core/str', 'local_processfeedback/submission/report_transfer', 'local_processfeedback/utils/logger'], function(__dep0, __dep1, __dep2) {
const Str = __dep0;
const createProcessFeedbackButton = __dep1.createProcessFeedbackButton;
const DASHBOARD_TOOLBAR_CLASS = __dep1.DASHBOARD_TOOLBAR_CLASS;
const getProcessFeedbackZipLinks = __dep1.getProcessFeedbackZipLinks;
const sendZipLinksToProcessFeedback = __dep1.sendZipLinksToProcessFeedback;
const debugError = __dep2.debugError;
const debugLog = __dep2.debugLog;
// This file is part of Moodle - http://moodle.org/
//
// Moodle is free software: you can redistribute it and/or modify
// it under the terms of the GNU General Public License as published by
// the Free Software Foundation, either version 3 of the License, or
// (at your option) any later version.
//
// Moodle is distributed in the hope that it will be useful,
// but WITHOUT ANY WARRANTY; without even the implied warranty of
// MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the
// GNU General Public License for more details.
//
// You should have received a copy of the GNU General Public License
// along with Moodle.  If not, see <http://www.gnu.org/licenses/>.




const getLanguageString = (key, value = undefined) => Str.get_string(key, 'local_processfeedback', value);
const DASHBOARD_INIT_PENDING_DATA = 'processfeedbackDashboardReportInitialising';

const getAssignAction = (windowRef) => {
    try {
        return new URL(windowRef.location.href).searchParams.get('action') || '';
    } catch (error) {
        return '';
    }
};

const isAssignmentGradingTablePage = (windowRef) => getAssignAction(windowRef) === 'grading';

const getDashboardButtonPlacement = (links, documentRef) => {
    const firstLink = links[0];
    if (!firstLink) {
        return null;
    }

    const table = firstLink.closest('.generaltable, table, .submissionstatustable');
    if (table) {
        return {
            element: table,
            position: 'beforebegin',
        };
    }

    return {
        element: documentRef.querySelector('main') || documentRef.body,
        position: 'afterbegin',
    };
};

const createDashboardReportToolbar = async(documentRef) => {
    const toolbar = documentRef.createElement('div');
    toolbar.className = `${DASHBOARD_TOOLBAR_CLASS} mb-3`;

    const button = createProcessFeedbackButton(documentRef, await getLanguageString('reportdashboardbutton'));
    const badge = documentRef.createElement('span');
    badge.className = 'local-processfeedback-beta-badge';
    badge.textContent = await getLanguageString('reportbetabadge');
    button.append(badge);

    const status = documentRef.createElement('span');
    status.className = 'small text-muted';
    status.setAttribute('role', 'status');
    status.setAttribute('aria-live', 'polite');

    toolbar.append(button, status);
    return { toolbar, button, status };
};

const initProcessFeedbackDashboardButton = async(windowRef, documentRef) => {
    const root = documentRef.documentElement;
    if (documentRef.querySelector(`.${DASHBOARD_TOOLBAR_CLASS}`) ||
            root.dataset[DASHBOARD_INIT_PENDING_DATA] === 'true') {
        debugLog(windowRef, 'Dashboard report button skipped: toolbar already exists');
        return;
    }

    if (!isAssignmentGradingTablePage(windowRef)) {
        debugLog(windowRef, 'Dashboard report button skipped: not grading table page');
        return;
    }

    const links = getProcessFeedbackZipLinks(documentRef);
    if (links.length === 0) {
        debugLog(windowRef, 'Dashboard report button skipped: no ZIP links found');
        return;
    }

    const placement = getDashboardButtonPlacement(links, documentRef);
    if (!placement || !placement.element) {
        return;
    }

    let toolbar = null;
    let button = null;
    let status = null;
    try {
        root.dataset[DASHBOARD_INIT_PENDING_DATA] = 'true';
        ({ toolbar, button, status } = await createDashboardReportToolbar(documentRef));
        if (documentRef.querySelector(`.${DASHBOARD_TOOLBAR_CLASS}`)) {
            debugLog(windowRef, 'Dashboard report button skipped: toolbar was added while initialising');
            return;
        }
        placement.element.insertAdjacentElement(placement.position, toolbar);
    } finally {
        delete root.dataset[DASHBOARD_INIT_PENDING_DATA];
    }

    debugLog(windowRef, 'Dashboard report button initialised', {
        linkCount: links.length,
    });

    button.addEventListener('click', async () => {
        const currentLinks = getProcessFeedbackZipLinks(documentRef);
        if (currentLinks.length === 0) {
            status.textContent = await getLanguageString('reportnozipfiles');
            debugLog(windowRef, 'Dashboard report send skipped: no current ZIP links');
            return;
        }

        button.disabled = true;
        status.textContent = '';
        try {
            await sendZipLinksToProcessFeedback(currentLinks, button, status, windowRef, {
                isMoodleDashboard: 'true',
            });
        } catch (error) {
            button.disabled = false;
            status.textContent = error.message || await getLanguageString('reportsendfailed');
            debugError(windowRef, 'Dashboard report send failed!', error);
        }
    });
};
return { initProcessFeedbackDashboardButton };
});